47	error_t encrypt_batch(const base_pke_i& base_pke, curve_id curve, mem_t ek, mem_t label, const std::vector<mem_t>& xs,
48	                      buf_t& out_ciphertext) {
49	  if (const error_t rv =
50	          coinbase::api::detail::validate_mem_arg_max_size(ek, "ek", coinbase::api::detail::MAX_OPAQUE_BLOB_SIZE))
51	    return rv;
52	  if (const error_t rv = coinbase::api::detail::validate_mem_arg(label, "label")) return rv;
53	  if (const error_t rv = coinbase::api::detail::validate_mem_vec_arg(xs, "xs")) return rv;
54	  error_t rv = UNINITIALIZED_ERROR;
55	
56	  const auto icurve = to_internal_curve(curve);
57	  if (!icurve.valid()) return coinbase::error(E_BADARG, "unsupported curve");
58	
59	  if (xs.empty()) return coinbase::error(E_BADARG, "batch_count must be positive");
60	  if (xs.size() > static_cast<size_t>(coinbase::mpc::ec_pve_batch_t::MAX_BATCH_COUNT))
61	    return coinbase::error(E_RANGE, "batch too large");
62	
63	  // Defensive check: avoid large attacker-controlled allocations when converting `xs[i]` into bignums.
64	  const int max_x_size = icurve.order().get_bin_size();
65	  for (const auto& x : xs) {
66	    if (x.size > max_x_size) return coinbase::error(E_RANGE, "xs element too large", /*to_print_stack_trace=*/false);
67	  }
68	
69	  const int n = static_cast<int>(xs.size());
70	  std::vector<coinbase::crypto::bn_t> x_bn;
71	  x_bn.reserve(static_cast<size_t>(n));
72	  for (int i = 0; i < n; i++) x_bn.push_back(coinbase::crypto::bn_t::from_bin(xs[static_cast<size_t>(i)]));
73	
74	  base_pke_bridge_t bridge(base_pke);
75	  const coinbase::mem_t ek_mem(ek.data, ek.size);
76	
77	  coinbase::mpc::ec_pve_batch_t pve_ct(n);
78	
79	  out_ciphertext.free();
80	  rv = pve_ct.encrypt(bridge, coinbase::mpc::pve_keyref(ek_mem), label, icurve, x_bn);
81	  if (rv) return rv;
82	
83	  pve_batch_ciphertext_blob_v1_t blob;
84	  blob.batch_count = static_cast<uint32_t>(n);
85	  blob.ct = coinbase::convert(pve_ct);
86	  out_ciphertext = coinbase::convert(blob);
87	  return SUCCESS;
88	}
